PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?req ?slot ?definingFeature ?slotValue WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:InstanceSpecification_slot ?slot .
