BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?instance ?instanceName ?slot ?definingFeature ?featName ?value ?litValue WHERE {
  ?instance rdf:type vocab:instance%20specification .
  ?instance vocab:NamedElement_name ?instanceName .
  FILTER(CONTAINS(LCASE(STR(?instanceName)), LCASE("m3 alignment maximum time")))

  ?instance vocab:InstanceSpecification_slot ?slot .
  OPTIONAL { 
    ?slot vocab:Slot_definingFeature ?definingFeature .
    OPTIONAL { ?definingFeature vocab:NamedElement_name ?featName }
  }
  OPTIONAL { 
    ?slot vocab:Slot_value ?value .
    OPTIONAL { ?value vocab:LiteralString_value ?litValue }
  }
}
LIMIT 30

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?durationConstraint ?dcName ?spec ?min ?max ?expr WHERE {
  ?durationConstraint rdf:type vocab:duration%20constraint .
  OPTIONAL { ?durationConstraint vocab:NamedElement_name ?dcName }
  OPTIONAL { ?durationConstraint vocab:DurationConstraint_specification__from_DurationConstraint ?spec }
  OPTIONAL { 
    ?spec vocab:DurationInterval_min__from_DurationInterval ?min .
    ?spec vocab:DurationInterval_max__from_DurationInterval ?max .
  }
  OPTIONAL { ?spec vocab:Expression_expr ?expr }
}
LIMIT 30
